cURLPython <pre><code># 第一轮：发送请求，模型决定调用函数
curl -X POST "https://tokens.smartfashionai.cn/v1/chat/completions" \
  -H "Authorization: Bearer $API_KEY" \
  -H "Content-Type: application/json" \
  -d '{
    "model": "gpt-5.4",
    "messages": [
      {"role": "user", "content": "北京今天天气怎么样？"}
    ],
    "tools": [
      {
        "type": "function",
        "function": {
          "name": "get_weather",
          "description": "获取指定城市的当前天气",
          "parameters": {
            "type": "object",
            "properties": {
              "city": {"type": "string"}
            },
            "required": ["city"]
          }
        }
      }
    ],
    "tool_choice": "auto",
    "max_tokens": 1024
  }'

# 第二轮：将函数结果回传给模型
curl -X POST "https://tokens.smartfashionai.cn/v1/chat/completions" \
  -H "Authorization: Bearer $API_KEY" \
  -H "Content-Type: application/json" \
  -d '{
    "model": "gpt-5.4",
    "messages": [
      {"role": "user", "content": "北京今天天气怎么样？"},
      {"role": "assistant", "content": null, "tool_calls": [{"id": "call_abc123", "type": "function", "function": {"name": "get_weather", "arguments": "{\"city\": \"北京\"}"}}]},
      {"role": "tool", "tool_call_id": "call_abc123", "content": "北京今天晴，气温 22°C，微风"}
    ],
    "max_tokens": 1024
  }'
</code></pre> <pre><code>import json
from openai import OpenAI

client = OpenAI(
    api_key="your_api_key_here",
    base_url="https://tokens.smartfashionai.cn/v1"
)

def get_weather(city: str) -&gt; str:
    # 模拟天气查询
    return f"{city}今天晴，气温 22°C，微风"

messages = [{"role": "user", "content": "北京今天天气怎么样？"}]
tools = [
    {
        "type": "function",
        "function": {
            "name": "get_weather",
            "description": "获取指定城市的当前天气",
            "parameters": {
                "type": "object",
                "properties": {
                    "city": {"type": "string"}
                },
                "required": ["city"]
            }
        }
    }
]

# 第一轮：模型决定调用函数
response = client.chat.completions.create(
    model="gpt-5.4",
    messages=messages,
    tools=tools,
    tool_choice="auto",
    max_tokens=1024
)

assistant_message = response.choices[0].message
messages.append(assistant_message)

# 执行函数并回传结果
if assistant_message.tool_calls:
    for tool_call in assistant_message.tool_calls:
        args = json.loads(tool_call.function.arguments)
        result = get_weather(**args)
        messages.append({
            "role": "tool",
            "tool_call_id": tool_call.id,
            "content": result
        })

# 第二轮：模型根据函数结果生成最终回答
final_response = client.chat.completions.create(
    model="gpt-5.4",
    messages=messages,
    max_tokens=1024
)
print(final_response.choices[0].message.content)
</code></pre>

